/// Executor for SecurityEventResponse flow
pub struct SecurityEventResponseFlowExecutor<H: SecurityEventResponseStepHandler> {
    handler: Arc<H>,
}

impl<H: SecurityEventResponseStepHandler> SecurityEventResponseFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<SecurityEventResponseFlowInstance, FlowError> {
        let mut instance = SecurityEventResponseFlowInstance::new(instance_id);
        instance.status = SecurityEventResponseFlowStatus::Running;
        instance.current_step = Some(SecurityEventResponseFlowStep::AnalyzeEvent);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut SecurityEventResponseFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            SecurityEventResponseFlowStep::AnalyzeEvent => {
                self.handler.handle_analyze_event(instance).await?
            }
            SecurityEventResponseFlowStep::CheckResponseRequired => {
                let next = self.handler.evaluate_check_response_required(instance).await?;
                Some(next)
            }
            SecurityEventResponseFlowStep::ExecuteAutoResponse => {
                self.handler.handle_execute_auto_response(instance).await?
            }
            SecurityEventResponseFlowStep::LogResponse => {
                self.handler.handle_log_response(instance).await?
            }
            SecurityEventResponseFlowStep::LogResponseError => {
                self.handler.handle_log_response_error(instance).await?
            }
            SecurityEventResponseFlowStep::CheckNotification => {
                let next = self.handler.evaluate_check_notification(instance).await?;
                Some(next)
            }
            SecurityEventResponseFlowStep::NotifySecurityTeam => {
                self.handler.handle_notify_security_team(instance).await?
            }
            SecurityEventResponseFlowStep::CheckImmediateAttention => {
                self.handler.handle_check_immediate_attention(instance).await?
            }
            SecurityEventResponseFlowStep::HandleAttention => {
                let next = self.handler.evaluate_handle_attention(instance).await?;
                Some(next)
            }
            SecurityEventResponseFlowStep::AwaitManualResolution => {
                self.handler.handle_await_manual_resolution(instance).await?
            }
            SecurityEventResponseFlowStep::EscalateUnresolved => {
                self.handler.handle_escalate_unresolved(instance).await?
            }
            SecurityEventResponseFlowStep::AwaitEscalatedResolution => {
                self.handler.handle_await_escalated_resolution(instance).await?
            }
            SecurityEventResponseFlowStep::CreateEscalationTicket => {
                self.handler.handle_create_escalation_ticket(instance).await?
            }
            SecurityEventResponseFlowStep::CheckAutoResolve => {
                self.handler.handle_check_auto_resolve(instance).await?
            }
            SecurityEventResponseFlowStep::HandleAutoResolve => {
                let next = self.handler.evaluate_handle_auto_resolve(instance).await?;
                Some(next)
            }
            SecurityEventResponseFlowStep::AutoResolve => {
                self.handler.handle_auto_resolve(instance).await?
            }
            SecurityEventResponseFlowStep::LogAutoResolve => {
                self.handler.handle_log_auto_resolve(instance).await?
            }
            SecurityEventResponseFlowStep::AwaitResolution => {
                self.handler.handle_await_resolution(instance).await?
            }
            SecurityEventResponseFlowStep::LogResolution => {
                self.handler.handle_log_resolution(instance).await?
            }
            SecurityEventResponseFlowStep::MarkStale => {
                self.handler.handle_mark_stale(instance).await?
            }
            SecurityEventResponseFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = SecurityEventResponseFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut SecurityEventResponseFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != SecurityEventResponseFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut SecurityEventResponseFlowInstance) {
        instance.status = SecurityEventResponseFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut SecurityEventResponseFlowInstance, error: impl Into<String>) {
        instance.status = SecurityEventResponseFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = SecurityEventResponseFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, SecurityEventResponseFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = SecurityEventResponseFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = SecurityEventResponseFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = SecurityEventResponseFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = SecurityEventResponseFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
